bib  <- ReadBib("publications_eric_pante.bib", check = FALSE)
keys <- names(bib)

extra_links <- tibble(key = character(), preprint = character(), github = character(), recommendation = character())

rows <- tibble(
  key   = keys,
  entry = lapply(keys, function(k) bib[k])
) |>
  mutate(
    title        = map_chr(entry, ~ strip_braces(.x$title %||% "")),
    authors_card = map_chr(entry, fmt_authors_card),
    year         = map_chr(entry, ~ {
      y <- .x$year %||% .x$date %||% ""
      if (is.list(y)) y$year %||% "" else as.character(y)
    }),
    venue        = map_chr(entry, ~ strip_braces(.x$journal %||% .x$booktitle %||% .x$publisher %||% "")),
    abstract     = map_chr(entry, get_abstract),
    dataset_info = map_chr(entry, get_dataset_info),
    bibtex       = map_chr(entry, get_bibtex),

    doi          = map_chr(entry, ~ .x$doi %||% NA_character_),
    url_fallback = map_chr(entry, ~ .x$url %||% NA_character_),

    preprint_raw  = map_chr(entry, ~ { v <- .x$preprint;  if (is.null(v) || length(v)==0) NA_character_ else as.character(v[[1]]) }),
    github_raw = map_chr(entry, ~ { v <- .x$github; if (is.null(v) || length(v)==0) NA_character_ else as.character(v[[1]]) }),
    recommendation_raw = map_chr(entry, ~ { v <- .x$recommendation; if (is.null(v) || length(v)==0) NA_character_ else as.character(v[[1]]) }),

    has_preprint_key  = map_lgl(entry, ~ !is.null(.x$preprint)  && length(.x$preprint)  > 0),
    has_github_key = map_lgl(entry, ~ !is.null(.x$github) && length(.x$github) > 0),
    has_recommendation_key = map_lgl(entry, ~ !is.null(.x$recommendation) && length(.x$recommendation) > 0)
  ) |>
  left_join(extra_links, by = "key") |>
  mutate(
    preprint_val  = coalesce(preprint,  preprint_raw),
    github_val = coalesce(github, github_raw),
    recommendation_val = coalesce(recommendation, recommendation_raw)
  ) |>
  select(-any_of(c("preprint", "github","recommendation"))) |>
  mutate(
    preprint_url  = normalize_link(preprint_val),
    github_url = normalize_link(github_val),
    recommendation_url = normalize_link(recommendation_val)
  ) |>
  mutate(
    doi_url = normalize_link(
      if_else(
        nzchar(doi %||% ""),
        str_glue("https://doi.org/{doi}"),
        if_else(nzchar(preprint_url %||% ""), preprint_url, url_fallback)
      )
    )
  ) |>
  mutate(
    primary = map_lgl(entry, ~ tolower(as.character(.x$primary %||% "false")) == "true")
  ) |>
  arrange(desc(year), title)
